code = """import json
import pandas as pd
import re

# Load data
civic_file = locals()['var_functions.query_db:2']
with open(civic_file) as f:
    civic_docs = json.load(f)

funding_file = locals()['var_functions.query_db:40']
with open(funding_file) as f:
    funding_data = json.load(f)

funding_df = pd.DataFrame(funding_data)
funding_df['Amount'] = pd.to_numeric(funding_df['Amount'], errors='coerce')

# Step 1: Identify disaster-related projects from funding data
disaster_keywords = ['FEMA', 'CalOES', 'CalJPIA', 'disaster', 'fire']
disaster_funding = funding_df[
    funding_df['Project_Name'].str.contains('|'.join(disaster_keywords), case=False, na=False)
].copy()

print('Disaster funding records:', len(disaster_funding))
print('Total disaster funding available:', disaster_funding['Amount'].sum())

# Step 2: Extract project mentions from civic documents and check for 2022
document_text = ' '.join([doc['text'] for doc in civic_docs])

# For each disaster project, check if mentioned with 2022
matched_projects = []
total_funding = 0.0

for _, fund_record in disaster_funding.iterrows():
    project_name = fund_record['Project_Name']
    amount = fund_record['Amount']
    
    # Clean project name for searching (remove parentheses and content)
    clean_name = re.sub(r'\s*\([^)]*\)\s*', ' ', project_name).strip()
    search_name = clean_name if clean_name else project_name
    
    # Check if project is mentioned in documents with 2022
    # Look for project name AND 2022 within some distance
    pattern = r'[^.]{0,200}' + re.escape(search_name) + r'[^.]{0,300}'
    matches = re.findall(pattern, document_text, re.IGNORECASE)
    
    has_2022 = False
    for match in matches:
        if '2022' in match:
            # Check if it's about start/beginning
            if any(indicator in match.lower() for indicator in ['start', 'begin', 'design', 'construction', 'advertise']):
                has_2022 = True
                break
    
    # Also check for explicit 2022 in project name
    if '2022' in project_name:
        has_2022 = True
    
    if has_2022:
        matched_projects.append({
            'project': project_name,
            'amount': float(amount)
        })
        total_funding += amount

result = {
    'total_funding': total_funding,
    'projects_count': len(matched_projects),
    'sample_projects': matched_projects[:5]
}

print('Result:', result)

# Format output
output = 'Total funding: $' + format(result['total_funding'], ',.2f') + '\n'
output += 'Projects matched: ' + str(result['projects_count'])

print('__RESULT__:')
print(json.dumps(result))"""

